import React, { useState, useEffect } from 'react';
import { PieChart, Pie, Cell, BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer } from 'recharts';
import api from '../utils/api';

const COLORS = ['#ef4444', '#f97316', '#3b82f6'];

function StatCard({ label, value, unit = '' }) {
  return (
    <div className="bg-gray-900 rounded-lg border border-gray-800 p-5">
      <p className="text-gray-400 text-sm">{label}</p>
      <p className="text-3xl font-bold mt-1">{value}<span className="text-gray-500 text-lg">{unit}</span></p>
    </div>
  );
}

export default function MonitorPage() {
  const [stats, setStats] = useState(null);

  const fetchStats = async () => {
    try {
      const { data } = await api.get('/monitor');
      setStats(data);
    } catch (err) {
      console.error(err);
    }
  };

  useEffect(() => {
    fetchStats();
    const interval = setInterval(fetchStats, 10000);
    return () => clearInterval(interval);
  }, []);

  if (!stats) return <div className="text-gray-500 text-center py-20">Chargement...</div>;

  const canalData = stats.byCanal.map((c) => ({ name: c.canal, value: c._count }));
  const categorieData = stats.byCategorie.map((c) => ({ name: c.categorie, value: c._count }));

  return (
    <div className="space-y-6">
      <h1 className="text-2xl font-bold">Monitoring</h1>

      <div className="grid grid-cols-2 md:grid-cols-5 gap-4">
        <StatCard label="Total Leads" value={stats.totalLeads} />
        <StatCard label="Messages envoyés" value={stats.totalMessages} />
        <StatCard label="Taux d'ouverture" value={stats.openRate} unit="%" />
        <StatCard label="Taux de clic" value={stats.clickRate} unit="%" />
        <StatCard label="Taux de réponse" value={stats.replyRate} unit="%" />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="bg-gray-900 rounded-lg border border-gray-800 p-5">
          <h2 className="text-sm font-semibold text-gray-400 mb-4">Leads par catégorie</h2>
          <ResponsiveContainer width="100%" height={200}>
            <PieChart>
              <Pie data={categorieData} dataKey="value" nameKey="name" cx="50%" cy="50%" outerRadius={80} label={({ name, value }) => `${name}: ${value}`}>
                {categorieData.map((_, i) => <Cell key={i} fill={COLORS[i % COLORS.length]} />)}
              </Pie>
              <Tooltip contentStyle={{ background: '#1f2937', border: 'none' }} />
            </PieChart>
          </ResponsiveContainer>
        </div>

        <div className="bg-gray-900 rounded-lg border border-gray-800 p-5">
          <h2 className="text-sm font-semibold text-gray-400 mb-4">Messages par canal</h2>
          <ResponsiveContainer width="100%" height={200}>
            <BarChart data={canalData}>
              <XAxis dataKey="name" stroke="#6b7280" tick={{ fontSize: 12 }} />
              <YAxis stroke="#6b7280" tick={{ fontSize: 12 }} />
              <Tooltip contentStyle={{ background: '#1f2937', border: 'none' }} />
              <Bar dataKey="value" fill="#6366f1" radius={[4, 4, 0, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      <div className="bg-gray-900 rounded-lg border border-gray-800 p-5">
        <h2 className="text-sm font-semibold text-gray-400 mb-3">Derniers leads</h2>
        <div className="space-y-2">
          {stats.recentLeads.map((l, i) => (
            <div key={i} className="flex items-center justify-between py-2 border-b border-gray-800 last:border-0">
              <span className="font-medium">{l.nom}</span>
              <span className="text-gray-400 text-sm">Score: {l.score}/10</span>
              <span className={`text-xs px-2 py-0.5 rounded ${l.categorie === 'CHAUD' ? 'bg-red-500/20 text-red-400' : l.categorie === 'TIEDE' ? 'bg-orange-500/20 text-orange-400' : 'bg-blue-500/20 text-blue-400'}`}>
                {l.categorie}
              </span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
